module RefModule(CLK, RST, IN, EDGE_DET);
input CLK, RST, IN;
output EDGE_DET;
reg EDGE_DET;
reg prev_IN;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST) begin
        EDGE_DET <= 0;
        prev_IN <= 0;
    end else begin
        if (IN && !prev_IN)
            EDGE_DET <= 1;
        else
            EDGE_DET <= 0;
        prev_IN <= IN;
    end
end

endmodule
